# solution.py
"""Team_Collaboration_Manager.

A thread-safe, in-memory collaboration manager supporting users, projects,
tasks, messaging (with attachments and threaded replies), a performance
dashboard (completion metrics and peer ratings) and exportable reports
(CSV and PDF).

The public surface is intentionally small and deterministic so that it can be
driven by an injectable clock for testing.  Standard library only, ASCII only.
"""

import copy
import csv
import io
import threading
from dataclasses import dataclass, field
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional


# ---------------------------------------------------------------------------
# Enumerations
# ---------------------------------------------------------------------------
class TaskStatus(Enum):
    """Lifecycle states for a task."""

    NOT_STARTED = "not_started"
    IN_PROGRESS = "in_progress"
    COMPLETED = "completed"


class UserRole(Enum):
    """Authorization role for a user."""

    MEMBER = "member"
    ADMIN = "admin"


class ReportFormat(Enum):
    """Supported export formats."""

    CSV = "csv"
    PDF = "pdf"


class ReportType(Enum):
    """Kinds of reports the manager can produce."""

    PROJECT_PROGRESS = "project_progress"
    TEAM_PERFORMANCE = "team_performance"
    INDIVIDUAL_PERFORMANCE = "individual_performance"


# ---------------------------------------------------------------------------
# Exception hierarchy
# ---------------------------------------------------------------------------
class TeamCollaborationError(Exception):
    """Base class for all errors raised by the manager."""


class ValidationError(TeamCollaborationError):
    """Raised when input fails validation."""


class NotFoundError(TeamCollaborationError):
    """Raised when a referenced entity does not exist."""


class AuthorizationError(TeamCollaborationError):
    """Raised when an actor is not permitted to perform an action."""


class DuplicateError(TeamCollaborationError):
    """Raised when a uniqueness constraint is violated."""


class ConflictError(TeamCollaborationError):
    """Raised when an operation conflicts with current state."""


# ---------------------------------------------------------------------------
# Data models
# ---------------------------------------------------------------------------
@dataclass
class User:
    id: int
    username: str
    email: str
    role: UserRole
    created_at: datetime


@dataclass
class Project:
    id: int
    name: str
    start_date: datetime
    end_date: datetime
    owner_id: int
    description: str = ""


@dataclass
class Task:
    id: int
    project_id: int
    title: str
    status: TaskStatus = TaskStatus.NOT_STARTED
    assignee_id: Optional[int] = None
    deadline: Optional[datetime] = None
    started_at: Optional[datetime] = None
    completed_at: Optional[datetime] = None
    created_at: Optional[datetime] = None


@dataclass
class Attachment:
    filename: str
    size: int
    uploaded_by: int
    uploaded_at: datetime


@dataclass
class Message:
    id: int
    author_id: int
    body: str
    project_id: Optional[int] = None
    task_id: Optional[int] = None
    parent_id: Optional[int] = None
    attachments: List[Attachment] = field(default_factory=list)
    created_at: Optional[datetime] = None
    edited_at: Optional[datetime] = None


@dataclass
class Rating:
    id: int
    rater_id: int
    ratee_id: int
    score: int
    feedback: str = ""
    task_id: Optional[int] = None
    created_at: Optional[datetime] = None


# ---------------------------------------------------------------------------
# Stores (thin containers that share a single lock with the manager)
# ---------------------------------------------------------------------------
class _Store:
    """Base container.  All stores share the manager's reentrant lock so that
    cross-store operations can be performed atomically."""

    def __init__(self, lock):
        self._lock = lock


class UserStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self.items = {}  # type: Dict[int, User]
        self.by_username = {}  # type: Dict[str, int]
        self.by_email = {}  # type: Dict[str, int]


class ProjectStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self.items = {}  # type: Dict[int, Project]


class TaskStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self.items = {}  # type: Dict[int, Task]
        self.by_project = {}  # type: Dict[int, set]
        self.by_assignee = {}  # type: Dict[int, set]


class MessageStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self.items = {}  # type: Dict[int, Message]
        self.by_project = {}  # type: Dict[int, list]
        self.by_task = {}  # type: Dict[int, list]


class PerformanceStore(_Store):
    def __init__(self, lock):
        super().__init__(lock)
        self.ratings = {}  # type: Dict[int, Rating]
        self.by_ratee = {}  # type: Dict[int, list]


class ReportStore(_Store):
    """Reports are computed on demand; this store only carries the lock."""


# ---------------------------------------------------------------------------
# Manager
# ---------------------------------------------------------------------------
def _clone(obj):
    """Return a deep copy so callers cannot mutate stored state."""

    return copy.deepcopy(obj)


class TeamCollaborationManager:
    """Coordinates users, projects, tasks, messaging, performance and reports.

    All public methods are thread-safe.  A single reentrant lock is shared by
    the manager and every sub-store so that compound operations remain atomic.
    """

    def __init__(self, now=None):
        self._lock = threading.RLock()
        self._now = now if now is not None else datetime.now
        self._id_counter = 0

        self.users = UserStore(self._lock)
        self.projects = ProjectStore(self._lock)
        self.tasks = TaskStore(self._lock)
        self.messages = MessageStore(self._lock)
        self.performance = PerformanceStore(self._lock)
        self.reports = ReportStore(self._lock)

    # -- id generation ----------------------------------------------------
    def _next_id(self):
        with self._lock:
            self._id_counter += 1
            return self._id_counter

    # ------------------------------------------------------------------
    # User management
    # ------------------------------------------------------------------
    def register_user(self, username, email, role=UserRole.MEMBER):
        with self._lock:
            self._validate_username(username)
            self._validate_email(email)
            if not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")
            uname = username.strip()
            mail = email.strip()
            if uname in self.users.by_username:
                raise DuplicateError("username already exists")
            if mail in self.users.by_email:
                raise DuplicateError("email already exists")
            uid = self._next_id()
            user = User(
                id=uid,
                username=uname,
                email=mail,
                role=role,
                created_at=self._now(),
            )
            self.users.items[uid] = user
            self.users.by_username[uname] = uid
            self.users.by_email[mail] = uid
            return _clone(user)

    def get_user(self, user_id):
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))
            return _clone(user)

    def list_users(self):
        with self._lock:
            return [_clone(self.users.items[i]) for i in sorted(self.users.items)]

    def update_user(self, user_id, username=None, email=None, role=None):
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))

            uname = None
            if username is not None:
                self._validate_username(username)
                uname = username.strip()
                existing = self.users.by_username.get(uname)
                if existing is not None and existing != user_id:
                    raise DuplicateError("username already exists")

            mail = None
            if email is not None:
                self._validate_email(email)
                mail = email.strip()
                existing = self.users.by_email.get(mail)
                if existing is not None and existing != user_id:
                    raise DuplicateError("email already exists")

            if role is not None and not isinstance(role, UserRole):
                raise ValidationError("role must be a UserRole")

            if uname is not None:
                self.users.by_username.pop(user.username, None)
                user.username = uname
                self.users.by_username[uname] = user_id
            if mail is not None:
                self.users.by_email.pop(user.email, None)
                user.email = mail
                self.users.by_email[mail] = user_id
            if role is not None:
                user.role = role
            return _clone(user)

    def delete_user(self, user_id):
        with self._lock:
            user = self.users.items.get(user_id)
            if user is None:
                raise NotFoundError("user {0} not found".format(user_id))

            for project in self.projects.items.values():
                if project.owner_id == user_id:
                    raise ConflictError("user owns a project")

            assigned = self.tasks.by_assignee.get(user_id, set())
            for tid in assigned:
                if self.tasks.items[tid].status != TaskStatus.COMPLETED:
                    raise ConflictError("user has open tasks")

            for tid in list(assigned):
                self.tasks.items[tid].assignee_id = None
            self.tasks.by_assignee.pop(user_id, None)

            self.users.by_username.pop(user.username, None)
            self.users.by_email.pop(user.email, None)
            del self.users.items[user_id]

    # ------------------------------------------------------------------
    # Project management
    # ------------------------------------------------------------------
    def create_project(self, name, start_date, end_date, owner_id, description=""):
        with self._lock:
            if owner_id not in self.users.items:
                raise NotFoundError("owner {0} not found".format(owner_id))
            if not isinstance(name, str) or not name.strip():
                raise ValidationError("project name required")
            if end_date < start_date:
                raise ValidationError("end_date must not precede start_date")
            pid = self._next_id()
            project = Project(
                id=pid,
                name=name.strip(),
                start_date=start_date,
                end_date=end_date,
                owner_id=owner_id,
                description=description,
            )
            self.projects.items[pid] = project
            return _clone(project)

    def get_project(self, project_id):
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            return _clone(project)

    def list_projects(self):
        with self._lock:
            return [
                _clone(self.projects.items[i]) for i in sorted(self.projects.items)
            ]

    def update_project(
        self, project_id, name=None, start_date=None, end_date=None, description=None
    ):
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            if name is not None and (not isinstance(name, str) or not name.strip()):
                raise ValidationError("project name required")

            new_start = project.start_date if start_date is None else start_date
            new_end = project.end_date if end_date is None else end_date
            if new_end < new_start:
                raise ValidationError("end_date must not precede start_date")

            if name is not None:
                project.name = name.strip()
            if start_date is not None:
                project.start_date = start_date
            if end_date is not None:
                project.end_date = end_date
            if description is not None:
                project.description = description
            return _clone(project)

    def delete_project(self, project_id):
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))

            task_ids = list(self.tasks.by_project.get(project_id, set()))
            for tid in task_ids:
                task = self.tasks.items.pop(tid, None)
                if task is not None and task.assignee_id is not None:
                    bucket = self.tasks.by_assignee.get(task.assignee_id)
                    if bucket is not None:
                        bucket.discard(tid)
                for mid in list(self.messages.by_task.get(tid, [])):
                    self._remove_message(mid)
                self.messages.by_task.pop(tid, None)
            self.tasks.by_project.pop(project_id, None)

            for mid in list(self.messages.by_project.get(project_id, [])):
                self._remove_message(mid)
            self.messages.by_project.pop(project_id, None)

            del self.projects.items[project_id]

    # ------------------------------------------------------------------
    # Task management
    # ------------------------------------------------------------------
    def create_task(self, project_id, title, assignee_id=None, deadline=None):
        with self._lock:
            project = self.projects.items.get(project_id)
            if project is None:
                raise NotFoundError("project {0} not found".format(project_id))
            if assignee_id is not None and assignee_id not in self.users.items:
                raise NotFoundError("assignee {0} not found".format(assignee_id))
            if not isinstance(title, str) or not title.strip():
                raise ValidationError("task title required")
            if deadline is not None and deadline < project.start_date:
                raise ValidationError("deadline must not precede project start")

            tid = self._next_id()
            task = Task(
                id=tid,
                project_id=project_id,
                title=title.strip(),
                status=TaskStatus.NOT_STARTED,
                assignee_id=assignee_id,
                deadline=deadline,
                created_at=self._now(),
            )
            self.tasks.items[tid] = task
            self.tasks.by_project.setdefault(project_id, set()).add(tid)
            if assignee_id is not None:
                self.tasks.by_assignee.setdefault(assignee_id, set()).add(tid)
            return _clone(task)

    def get_task(self, task_id):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            return _clone(task)

    def list_tasks_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = sorted(self.tasks.by_project.get(project_id, set()))
            return [_clone(self.tasks.items[i]) for i in ids]

    def list_tasks_by_assignee(self, assignee_id):
        with self._lock:
            if assignee_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(assignee_id))
            ids = sorted(self.tasks.by_assignee.get(assignee_id, set()))
            return [_clone(self.tasks.items[i]) for i in ids]

    def assign_task(self, task_id, assignee_id):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if assignee_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(assignee_id))
            self._set_assignee(task, assignee_id)
            return _clone(task)

    def reassign_task(self, task_id, new_assignee_id):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if new_assignee_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(new_assignee_id))
            self._set_assignee(task, new_assignee_id)
            return _clone(task)

    def unassign_task(self, task_id):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            self._set_assignee(task, None)
            return _clone(task)

    def set_deadline(self, task_id, deadline):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if deadline is not None:
                project = self.projects.items.get(task.project_id)
                if project is not None and deadline < project.start_date:
                    raise ValidationError("deadline must not precede project start")
            task.deadline = deadline
            return _clone(task)

    def update_status(self, task_id, status):
        with self._lock:
            task = self.tasks.items.get(task_id)
            if task is None:
                raise NotFoundError("task {0} not found".format(task_id))
            if not isinstance(status, TaskStatus):
                raise ValidationError("status must be a TaskStatus")

            now = self._now()
            if status == TaskStatus.NOT_STARTED:
                task.started_at = None
                task.completed_at = None
            elif status == TaskStatus.IN_PROGRESS:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = None
            elif status == TaskStatus.COMPLETED:
                if task.started_at is None:
                    task.started_at = now
                task.completed_at = now
            task.status = status
            return _clone(task)

    # ------------------------------------------------------------------
    # Messaging
    # ------------------------------------------------------------------
    def post_message(
        self,
        author_id,
        body,
        project_id=None,
        task_id=None,
        attachments=None,
        parent_id=None,
    ):
        with self._lock:
            if (project_id is None) == (task_id is None):
                raise ValidationError("exactly one of project_id/task_id required")
            if author_id not in self.users.items:
                raise NotFoundError("author {0} not found".format(author_id))
            if project_id is not None and project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            if task_id is not None and task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))
            if parent_id is not None and parent_id not in self.messages.items:
                raise NotFoundError("parent {0} not found".format(parent_id))

            atts = list(attachments) if attachments else []
            text = body if isinstance(body, str) else ""
            if not text.strip() and not atts:
                raise ValidationError("message body or attachment required")

            now = self._now()
            attachment_objs = [
                Attachment(
                    filename=filename,
                    size=len(data),
                    uploaded_by=author_id,
                    uploaded_at=now,
                )
                for (filename, data) in atts
            ]
            mid = self._next_id()
            message = Message(
                id=mid,
                author_id=author_id,
                body=text,
                project_id=project_id,
                task_id=task_id,
                parent_id=parent_id,
                attachments=attachment_objs,
                created_at=now,
                edited_at=None,
            )
            self.messages.items[mid] = message
            if project_id is not None:
                self.messages.by_project.setdefault(project_id, []).append(mid)
            if task_id is not None:
                self.messages.by_task.setdefault(task_id, []).append(mid)
            return _clone(message)

    def edit_message(self, message_id, editor_id, new_body):
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != editor_id:
                raise AuthorizationError("only the author may edit")
            empty = not isinstance(new_body, str) or not new_body.strip()
            if empty and not message.attachments:
                raise ValidationError("message body or attachment required")
            message.body = new_body
            message.edited_at = self._now()
            return _clone(message)

    def add_attachment(self, message_id, uploader_id, filename, data):
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != uploader_id:
                raise AuthorizationError("only the author may attach")
            if not isinstance(filename, str) or not filename.strip():
                raise ValidationError("filename required")
            attachment = Attachment(
                filename=filename,
                size=len(data),
                uploaded_by=uploader_id,
                uploaded_at=self._now(),
            )
            message.attachments.append(attachment)
            return _clone(message)

    def list_messages_by_project(self, project_id):
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = sorted(self.messages.by_project.get(project_id, []))
            return [_clone(self.messages.items[i]) for i in ids]

    def list_messages_by_task(self, task_id):
        with self._lock:
            if task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))
            ids = sorted(self.messages.by_task.get(task_id, []))
            return [_clone(self.messages.items[i]) for i in ids]

    def delete_message(self, message_id, requester_id):
        with self._lock:
            message = self.messages.items.get(message_id)
            if message is None:
                raise NotFoundError("message {0} not found".format(message_id))
            if message.author_id != requester_id:
                raise AuthorizationError("only the author may delete")
            self._remove_message(message_id)

    # ------------------------------------------------------------------
    # Performance dashboard
    # ------------------------------------------------------------------
    def get_completion_rate(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            ids = self.tasks.by_assignee.get(user_id, set())
            if not ids:
                return 0.0
            completed = sum(
                1
                for i in ids
                if self.tasks.items[i].status == TaskStatus.COMPLETED
            )
            return completed / len(ids)

    def get_average_completion_time(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            durations = self._completion_durations(
                self.tasks.by_assignee.get(user_id, set())
            )
            if not durations:
                return None
            return sum(durations) / len(durations)

    def submit_rating(self, rater_id, ratee_id, score, feedback="", task_id=None):
        with self._lock:
            if rater_id not in self.users.items:
                raise NotFoundError("rater {0} not found".format(rater_id))
            if ratee_id not in self.users.items:
                raise NotFoundError("ratee {0} not found".format(ratee_id))
            if rater_id == ratee_id:
                raise ConflictError("users cannot rate themselves")
            if isinstance(score, bool) or not isinstance(score, int):
                raise ValidationError("score must be an integer 1-5")
            if score < 1 or score > 5:
                raise ValidationError("score must be between 1 and 5")
            if task_id is not None and task_id not in self.tasks.items:
                raise NotFoundError("task {0} not found".format(task_id))

            rid = self._next_id()
            rating = Rating(
                id=rid,
                rater_id=rater_id,
                ratee_id=ratee_id,
                score=score,
                feedback=feedback,
                task_id=task_id,
                created_at=self._now(),
            )
            self.performance.ratings[rid] = rating
            self.performance.by_ratee.setdefault(ratee_id, []).append(rid)
            return _clone(rating)

    def get_ratings_summary(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            ids = sorted(self.performance.by_ratee.get(user_id, []))
            ratings = [self.performance.ratings[i] for i in ids]
            count = len(ratings)
            average = sum(r.score for r in ratings) / count if count else 0.0
            return {
                "count": count,
                "average": average,
                "ratings": [_clone(r) for r in ratings],
            }

    def get_user_dashboard(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            ids = self.tasks.by_assignee.get(user_id, set())
            tasks = [self.tasks.items[i] for i in ids]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            in_progress = sum(
                1 for t in tasks if t.status == TaskStatus.IN_PROGRESS
            )
            not_started = sum(
                1 for t in tasks if t.status == TaskStatus.NOT_STARTED
            )
            completion_rate = completed / total if total else 0.0
            durations = self._completion_durations(ids)
            avg_time = sum(durations) / len(durations) if durations else None

            rating_ids = self.performance.by_ratee.get(user_id, [])
            rating_count = len(rating_ids)
            rating_average = (
                sum(self.performance.ratings[i].score for i in rating_ids)
                / rating_count
                if rating_count
                else 0.0
            )
            return {
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "in_progress_tasks": in_progress,
                "not_started_tasks": not_started,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
            }

    # ------------------------------------------------------------------
    # Reports
    # ------------------------------------------------------------------
    def project_progress_report(self, project_id):
        with self._lock:
            if project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))
            ids = self.tasks.by_project.get(project_id, set())
            tasks = [self.tasks.items[i] for i in ids]
            total = len(tasks)
            status_counts = {status.value: 0 for status in TaskStatus}
            for task in tasks:
                status_counts[task.status.value] += 1
            completed = status_counts[TaskStatus.COMPLETED.value]
            completion_rate = completed / total if total else 0.0
            now = self._now()
            overdue = sum(
                1
                for task in tasks
                if task.deadline is not None
                and task.deadline < now
                and task.status != TaskStatus.COMPLETED
            )
            per_assignee = {}
            for task in tasks:
                if task.assignee_id is None:
                    continue
                bucket = per_assignee.setdefault(
                    task.assignee_id, {"total": 0, "completed": 0}
                )
                bucket["total"] += 1
                if task.status == TaskStatus.COMPLETED:
                    bucket["completed"] += 1
            for bucket in per_assignee.values():
                bucket["completion_rate"] = (
                    bucket["completed"] / bucket["total"] if bucket["total"] else 0.0
                )
            return {
                "report_type": ReportType.PROJECT_PROGRESS.value,
                "project_id": project_id,
                "total_tasks": total,
                "status_counts": status_counts,
                "completion_rate": completion_rate,
                "overdue_tasks": overdue,
                "per_assignee": per_assignee,
            }

    def team_performance_report(self, project_id=None):
        with self._lock:
            if project_id is not None and project_id not in self.projects.items:
                raise NotFoundError("project {0} not found".format(project_id))

            user_ids = set()
            for task in self.tasks.items.values():
                if task.assignee_id is None:
                    continue
                if project_id is not None and task.project_id != project_id:
                    continue
                user_ids.add(task.assignee_id)

            rows = []
            for uid in sorted(user_ids):
                task_ids = [
                    i
                    for i in self.tasks.by_assignee.get(uid, set())
                    if project_id is None
                    or self.tasks.items[i].project_id == project_id
                ]
                tasks = [self.tasks.items[i] for i in task_ids]
                total = len(tasks)
                completed = sum(
                    1 for t in tasks if t.status == TaskStatus.COMPLETED
                )
                completion_rate = completed / total if total else 0.0
                durations = self._completion_durations(task_ids)
                avg_time = (
                    sum(durations) / len(durations) if durations else None
                )
                rating_ids = self.performance.by_ratee.get(uid, [])
                rating_count = len(rating_ids)
                rating_average = (
                    sum(self.performance.ratings[i].score for i in rating_ids)
                    / rating_count
                    if rating_count
                    else 0.0
                )
                user = self.users.items.get(uid)
                rows.append(
                    {
                        "user_id": uid,
                        "username": user.username if user else "",
                        "total_tasks": total,
                        "completed_tasks": completed,
                        "completion_rate": completion_rate,
                        "average_completion_time": avg_time,
                        "rating_count": rating_count,
                        "rating_average": rating_average,
                    }
                )
            return {
                "report_type": ReportType.TEAM_PERFORMANCE.value,
                "project_id": project_id,
                "rows": rows,
            }

    def individual_performance_report(self, user_id):
        with self._lock:
            if user_id not in self.users.items:
                raise NotFoundError("user {0} not found".format(user_id))
            ids = sorted(self.tasks.by_assignee.get(user_id, set()))
            tasks = [self.tasks.items[i] for i in ids]
            total = len(tasks)
            completed = sum(1 for t in tasks if t.status == TaskStatus.COMPLETED)
            completion_rate = completed / total if total else 0.0
            durations = self._completion_durations(ids)
            avg_time = sum(durations) / len(durations) if durations else None

            rating_ids = self.performance.by_ratee.get(user_id, [])
            rating_count = len(rating_ids)
            rating_average = (
                sum(self.performance.ratings[i].score for i in rating_ids)
                / rating_count
                if rating_count
                else 0.0
            )
            task_rows = [
                {
                    "task_id": t.id,
                    "title": t.title,
                    "status": t.status.value,
                    "started_at": t.started_at.isoformat() if t.started_at else "",
                    "completed_at": (
                        t.completed_at.isoformat() if t.completed_at else ""
                    ),
                    "deadline": t.deadline.isoformat() if t.deadline else "",
                }
                for t in tasks
            ]
            return {
                "report_type": ReportType.INDIVIDUAL_PERFORMANCE.value,
                "user_id": user_id,
                "total_tasks": total,
                "completed_tasks": completed,
                "completion_rate": completion_rate,
                "average_completion_time": avg_time,
                "rating_count": rating_count,
                "rating_average": rating_average,
                "tasks": task_rows,
            }

    def export_report(self, report, report_format):
        with self._lock:
            if not isinstance(report_format, ReportFormat):
                raise ValidationError("report_format must be a ReportFormat")
            if not isinstance(report, dict):
                raise ValidationError("report must be a mapping")
            if report_format == ReportFormat.CSV:
                return self._export_csv(report)
            return self._export_pdf(report)

    # ------------------------------------------------------------------
    # Internal helpers
    # ------------------------------------------------------------------
    def _validate_username(self, username):
        if not isinstance(username, str) or not username.strip():
            raise ValidationError("username required")

    def _validate_email(self, email):
        if not isinstance(email, str) or not email.strip() or "@" not in email:
            raise ValidationError("valid email required")

    def _set_assignee(self, task, new_id):
        old = task.assignee_id
        if old is not None:
            bucket = self.tasks.by_assignee.get(old)
            if bucket is not None:
                bucket.discard(task.id)
        task.assignee_id = new_id
        if new_id is not None:
            self.tasks.by_assignee.setdefault(new_id, set()).add(task.id)

    def _remove_message(self, message_id):
        message = self.messages.items.pop(message_id, None)
        if message is None:
            return
        if message.project_id is not None:
            bucket = self.messages.by_project.get(message.project_id)
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)
        if message.task_id is not None:
            bucket = self.messages.by_task.get(message.task_id)
            if bucket is not None and message_id in bucket:
                bucket.remove(message_id)

    def _completion_durations(self, task_ids):
        durations = []
        for i in task_ids:
            task = self.tasks.items.get(i)
            if (
                task is not None
                and task.status == TaskStatus.COMPLETED
                and task.started_at is not None
                and task.completed_at is not None
            ):
                durations.append((task.completed_at - task.started_at).total_seconds())
        return durations

    def _report_table(self, report):
        """Return (header, rows) of strings for a tabular CSV rendering."""

        report_type = report.get("report_type")
        if report_type == ReportType.TEAM_PERFORMANCE.value:
            header = [
                "user_id",
                "username",
                "total_tasks",
                "completed_tasks",
                "completion_rate",
                "average_completion_time",
                "rating_count",
                "rating_average",
            ]
            rows = [
                [row.get(column, "") for column in header]
                for row in report.get("rows", [])
            ]
            return header, rows
        if report_type == ReportType.INDIVIDUAL_PERFORMANCE.value:
            header = [
                "task_id",
                "title",
                "status",
                "started_at",
                "completed_at",
                "deadline",
            ]
            rows = [
                [task.get(column, "") for column in header]
                for task in report.get("tasks", [])
            ]
            return header, rows
        # project_progress and any other shape: flatten to metric/value pairs.
        header = ["metric", "value"]
        rows = [[key, report[key]] for key in report]
        return header, rows

    def _export_csv(self, report):
        header, rows = self._report_table(report)
        buffer = io.StringIO()
        writer = csv.writer(buffer)
        writer.writerow(header)
        for row in rows:
            writer.writerow(row)
        return buffer.getvalue()

    def _export_pdf(self, report):
        header, rows = self._report_table(report)
        lines = ["Report: {0}".format(report.get("report_type", "report"))]
        lines.append(" | ".join(str(column) for column in header))
        for row in rows:
            lines.append(" | ".join(str(cell) for cell in row))
        return _build_pdf(lines)


# ---------------------------------------------------------------------------
# Minimal PDF writer
# ---------------------------------------------------------------------------
def _escape_pdf_text(text):
    return (
        text.replace("\\", "\\\\").replace("(", "\\(").replace(")", "\\)")
    )


def _build_pdf(lines):
    """Build a small but structurally valid single-page PDF document.

    Only the leading ``%PDF-`` signature is contractually required by callers,
    but a well-formed cross-reference table is emitted so the bytes open in a
    standard viewer.
    """

    if not lines:
        lines = [""]

    content_parts = ["BT", "/F1 12 Tf", "50 760 Td", "14 TL"]
    for index, line in enumerate(lines):
        safe = _escape_pdf_text(str(line))
        if index == 0:
            content_parts.append("({0}) Tj".format(safe))
        else:
            content_parts.append("T* ({0}) Tj".format(safe))
    content_parts.append("ET")
    content_stream = "\n".join(content_parts).encode("latin-1", "replace")

    objects = []
    objects.append(b"<< /Type /Catalog /Pages 2 0 R >>")
    objects.append(b"<< /Type /Pages /Kids [3 0 R] /Count 1 >>")
    objects.append(
        b"<< /Type /Page /Parent 2 0 R /MediaBox [0 0 612 792] "
        b"/Contents 4 0 R /Resources << /Font << /F1 5 0 R >> >> >>"
    )
    objects.append(
        b"<< /Length "
        + str(len(content_stream)).encode("latin-1")
        + b" >>\nstream\n"
        + content_stream
        + b"\nendstream"
    )
    objects.append(
        b"<< /Type /Font /Subtype /Type1 /BaseFont /Helvetica >>"
    )

    out = bytearray()
    out += b"%PDF-1.4\n"
    offsets = []
    for index, body in enumerate(objects, start=1):
        offsets.append(len(out))
        out += "{0} 0 obj\n".format(index).encode("latin-1")
        out += body
        out += b"\nendobj\n"

    xref_position = len(out)
    count = len(objects) + 1
    out += "xref\n0 {0}\n".format(count).encode("latin-1")
    out += b"0000000000 65535 f \n"
    for offset in offsets:
        out += "{0:010d} 00000 n \n".format(offset).encode("latin-1")
    out += "trailer\n<< /Size {0} /Root 1 0 R >>\n".format(count).encode("latin-1")
    out += b"startxref\n"
    out += "{0}\n".format(xref_position).encode("latin-1")
    out += b"%%EOF"
    return bytes(out)
